class carEngine{constructor(_pm){this._={audio:null,position:null,speed:0,enginePitch:1,frames:0}}loop(d){try{this._.maxSpeed=this._.power+Math.random()*5+Math.sin(Date.now()/153)-Math.min(Math.tan(Date.now()/245),4);if(this._.play)this._.speed<this._.maxSpeed?(this._.speed=this._.speed+0.2+Math.pow(100-this._.speed,1.6)/500):(this._.speed=this._.maxSpeed);else this._.speed>0?(this._.speed=this._.speed-0.2-Math.pow(this._.speed,1.4)/1000):(this._.speed=0);this._.enginePitch=1+this._.speed/100;if(this._.audio&&this._.frames%2==0)this._.audio.source.playbackRate.value=1+this._.speed/40;this._.audio.position.copy(this._.position)}catch(error){}requestAnimationFrame(()=>this.loop({}))}accelerate(d){this._.power=d.power;this._.position=d.position;this._.play=!0;this._.audio.setVolume(this._.power/160+.34)}decelerate(d){this._.power=0;this._.audio.setVolume(.34);delete this._.play}move(d){this._.audio.setVolume(.34)}halt(d){this._.audio.setVolume(.01)}load(d){this._.audio=d.audio;this._.position=d.position;d.loader.load(d.url,(buffer)=>{d.audio.setBuffer(buffer);d.audio.setLoop(!0);d.audio.setRefDistance(14);d.audio.play()});this._.audio.setVolume(.34);this.loop({})}}export{carEngine}